package org.eclipse.rdf4j.sail.helpers;

import static org.assertj.core.api.Assertions.assertThat;

import org.eclipse.rdf4j.query.Query;
import org.junit.jupiter.api.Test;

class SlowQueryContextHolderTest {

	@Test
	void restoreNestedContext() {
		assertThat(SlowQueryContextHolder.get()).isNull();

		SlowQueryContextHolder.SlowQueryContext previousOuter = SlowQueryContextHolder
				.set("SELECT * WHERE { ?s ?p ?o }", Query.QueryType.TUPLE);
		try {
			SlowQueryContextHolder.SlowQueryContext outer = SlowQueryContextHolder.get();
			assertThat(previousOuter).isNull();
			assertThat(outer).isNotNull();
			assertThat(outer.getQueryType()).isEqualTo(Query.QueryType.TUPLE);
			assertThat(outer.getRawQueryText()).contains("SELECT");

			SlowQueryContextHolder.SlowQueryContext previousInner = SlowQueryContextHolder
					.set("ASK WHERE { ?s ?p ?o }", Query.QueryType.BOOLEAN);
			try {
				assertThat(previousInner).isSameAs(outer);
				assertThat(SlowQueryContextHolder.get().getQueryType()).isEqualTo(Query.QueryType.BOOLEAN);
				assertThat(SlowQueryContextHolder.get().getRawQueryText()).contains("ASK");
			} finally {
				SlowQueryContextHolder.restore(previousInner);
			}

			assertThat(SlowQueryContextHolder.get()).isSameAs(outer);
		} finally {
			SlowQueryContextHolder.restore(previousOuter);
		}

		assertThat(SlowQueryContextHolder.get()).isNull();
	}
}
